mapper.select:
SELECT team.* 
FROM fc_java.team_info team
JOIN fc_java.pl_info player
ON team.t_num = player.t_num 
WHERE player.id = #{id}
ORDER BY player.pl_ap_date DESC;

	SELECT *
    FROM fc_java.team_info
